  const key = `${name}=`
  const parts = document.cookie.split(';')
  for (const part of parts) {
    const trimmed = part.trim()
    if (!trimmed.startsWith(key)) continue
    return decodeURIComponent(trimmed.slice(key.length))
  }
  return null
}

